+		return -ENOMEM;
 	spi_sub_ptr = spi_bus->spi_int[iter];

function_code:
static int pci1xxxx_spi_probe(struct pci_dev *pdev)
{
	spi_bus->spi_int[iter] = devm_kzalloc(&pdev->dev, sizeof(*spi_bus->spi_int[iter]), GFP_KERNEL);
	spi_sub_ptr = spi_bus->spi_int[iter];
	spi_sub_ptr->spi_host = devm_spi_alloc_host(...);
	return 0;
}

