patch:
--- a/drivers/net/device.c
+++ b/drivers/net/device.c
@@ -88,6 +88,8 @@ static int net_device_probe(struct device *dev)
 	data = kzalloc(sizeof(*data), GFP_KERNEL);
+	if (!data)
+		return -ENOMEM;
 	dev_set_drvdata(dev, data);

function_code:
static int net_device_probe(struct device *dev)
{
	data = kzalloc(sizeof(*data), GFP_KERNEL);
	dev_set_drvdata(dev, data);
	return 0;
}

patch:
--- a/drivers/crypto/crypto_dev.c
+++ b/drivers/crypto/crypto_dev.c
@@ -200,7 +200,6 @@ static void crypto_cleanup(struct crypto_ctx *ctx)
 	if (ctx->buf) {
 		kfree(ctx->buf);
-		kfree(ctx->buf);
 		ctx->buf = NULL;
 	}

function_code:
static void crypto_cleanup(struct crypto_ctx *ctx)
{
	if (ctx->buf) {
		kfree(ctx->buf);
		ctx->buf = NULL;
	}
}
